from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql

app = Flask(__name__)

def get_db_connection():
    conn = psycopg2.connect(
        dbname="yourdbname",
        user="youruser",
        password="yourpassword",
        host="yourhost",
        port="yourport"
    )
    return conn

@app.route('/query', methods=['POST'])
def query_database():
    data = request.json
    table = data.get('table')
    columns = data.get('columns', '*')
    conditions = data.get('conditions', {})

    if not table:
        return jsonify({"error": "Table name is required"}), 400

    try:
        conn = get_db_connection()
        cur = conn.cursor()

        # Build the SQL query dynamically and safely
        query = sql.SQL("SELECT {fields} FROM {table} {where_clause}").format(
            fields=sql.SQL(', ').join(map(sql.Identifier, columns)) if columns != '*' else sql.SQL('*'),
            table=sql.Identifier(table),
            where_clause=sql.SQL('WHERE {}').format(
                sql.SQL(' AND ').join(
                    sql.Composed([
                        sql.Identifier(k), 
                        sql.SQL('='),
                        sql.Placeholder(k)
                    ]) for k in conditions.keys()
                )
            ) if conditions else sql.SQL('')
        )

        cur.execute(query, conditions)
        results = cur.fetchall()
        cur.close()
        conn.close()

        return jsonify(results)

    except Exception as e:
        return jsonify({"error": str(e)}), 500

